const track=e=>{if(_PHK&&window.posthog?.capture)window.posthog.capture(e,{v:'3.7',t:Date.now()});if(!_EP)return;try{const p=JSON.stringify({e,v:'3.7',t:Date.now()});navigator.sendBeacon?navigator.sendBeacon(_EP,p):fetch(_EP,{method:'POST',body:p,keepalive:true}).catch(()=>{});}catch{}};

