    {(()=>{const winPct=dynastyStats.seasons>0&&(dynastyStats.wins+dynastyStats.losses)>0?Math.round(dynastyStats.wins/(dynastyStats.wins+dynastyStats.losses)*100):50;return(<div style={{background:C.cd,borderRadius:6,padding:8,marginBottom:8,border:`1px solid ${C.bd}`}}><div style={{fontSize:12,fontWeight:800,color:C.gd,marginBottom:5}}>🏆 DYNASTY RECORD</div><div style={{display:'flex',gap:12,flexWrap:'wrap'}}>{[['SEASONS',dynastyStats.seasons],['W-L',`${dynastyStats.wins}-${dynastyStats.losses}`],['WIN%',`${winPct}%`],['PLAYOFF APPS',dynastyStats.playoffApps],['CHAMPIONSHIPS',dynastyStats.championships]].map(([l,v])=><div key={l} style={{textAlign:'center'}}><div style={{fontSize:14,fontWeight:900,color:l==='CHAMPIONSHIPS'&&dynastyStats.championships>0?C.gd:C.tx}}>{v}</div><div style={{fontSize:10,color:C.mt}}>{l}</div></div>)}</div></div>);})()}{awards.length>0&&(()=>{const curAw=awards.find(a=>a.yr===yr)||awards[awards.length-1];const histAw=awards.filter(a=>a.yr<yr).slice(-3).reverse();return(<div style={{marginBottom:8,border:`1px solid ${C.gd}44`,borderRadius:5}}><div style={{padding:"6px 8px",fontSize:12,fontWeight:700,color:C.gd}}>🏆 SEASON AWARDS {curAw?.yr}</div>{curAw&&<div style={{padding:"4px 8px 8px"}}>{[['MVP',curAw.mvp,'#f59e0b'],['DPOY',curAw.dpoy,'#3b82f6'],['OROY',curAw.oroy,'#22c55e'],['DROY',curAw.droy,'#a78bfa']].map(([lbl,w,col])=>w&&<div key={lbl} style={{fontSize:12,padding:"2px 0",color:"#94a3b8"}}><span style={{color:col,fontWeight:700,minWidth:36,display:"inline-block"}}>🏆 {lbl}</span> {w.name} ({w.team}) — {w.stat}</div>)}</div>}{histAw.length>0&&<div style={{padding:"0 8px 6px",borderTop:`1px solid ${C.bd}22`}}><div style={{fontSize:11,color:C.mt,marginTop:4,marginBottom:2}}>HISTORY</div>{histAw.map(a=>a&&<div key={a.yr} style={{fontSize:11,color:"#475569"}}>Yr{a.yr}: MVP {a.mvp?.name||'?'} | DPOY {a.dpoy?.name||'?'} | OROY {a.oroy?.name||'?'} | DROY {a.droy?.name||'?'}</div>)}</div>}</div>);})()}{news.length>0&&<div style={{marginBottom:8,border:`1px solid ${C.bd}`,borderRadius:5}}><div onClick={()=>setNewsOpen(o=>!o)} style={{padding:"6px 8px",cursor:"pointer",display:"flex",justifyContent:"space-between",alignItems:"center",fontSize:12,fontWeight:700,color:"#38bdf8"}}><span>📡 LEAGUE NEWS ({news.length})</span><span>{newsOpen?"▲":"▼"}</span></div>{newsOpen&&<div style={{padding:"4px 8px 8px"}}>{news.map((n,i)=><div key={i} style={{padding:"2px 4px",fontSize:12,color:"#94a3b8",borderBottom:`1px solid ${C.bd}11`}}>{n}</div>)}</div>}</div>}
    {/* v36: Dynasty Record Book — per-season history timeline */}
