    {spectatorGame&&<div style={{position:'fixed',inset:0,background:'rgba(0,0,0,.92)',zIndex:2900,display:'flex',alignItems:'center',justifyContent:'center',padding:16}} onClick={()=>setSpectatorGame(null)}><div style={{background:'#0d1424',borderRadius:12,padding:16,maxWidth:360,width:'100%',border:'1px solid #334155'}}><div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:8}}><div style={{fontWeight:900,fontSize:15}}>{teams[spectatorGame.game.h]?.ab} {spectatorGame.hs} — {spectatorGame.as} {teams[spectatorGame.game.a]?.ab}</div><span style={{fontSize:11,color:'#64748b'}}>FINAL</span></div><div style={{maxHeight:150,overflowY:'auto',marginBottom:8}}>{spectatorLog.map((l,i)=><div key={i} style={{fontSize:11,color:'#64748b',padding:'1px 0'}}>{l}</div>)}</div><button onClick={()=>setSpectatorGame(null)} style={{width:'100%',background:'#1e293b',color:C.mt,border:'none',borderRadius:5,padding:'6px 0',fontSize:12,cursor:'pointer'}}>Close</button></div></div>}
    {/* v30: Rehab Choices Modal */}
    {Object.keys(rehabChoices).length>0&&<div style={{position:'fixed',inset:0,background:'rgba(0,0,0,.88)',zIndex:2950,display:'flex',alignItems:'center',justifyContent:'center',padding:16}}><div style={{background:'#0d1424',borderRadius:12,padding:14,maxWidth:320,width:'100%',border:'1px solid #ef444455'}}><div style={{fontSize:13,fontWeight:800,color:'#fca5a5',marginBottom:8}}>🏥 INJURY REHAB PROTOCOL</div>{Object.entries(rehabChoices).slice(0,1).map(([pid,rc])=><div key={pid}><div style={{fontSize:12,color:'#e2e8f0',marginBottom:8}}><b>{rc.name}</b> ({rc.pos}) — {rc.wksLeft} wks remaining on IR</div><div style={{fontSize:11,color:C.mt,marginBottom:6}}>Choose rehab approach:</div><div style={{display:'flex',flexDirection:'column',gap:4}}>{[{id:'aggressive',lbl:'🔥 Aggressive',desc:'Return 2wks early, 15% re-injury risk',wkBonus:-2,risk:0.15},{id:'standard',lbl:'🏃 Standard',desc:'Normal timeline, low risk',wkBonus:0,risk:0.05},{id:'cautious',lbl:'🛡 Cautious',desc:'+1wk extra, near-zero re-injury',wkBonus:1,risk:0.01}].map(opt=><button key={opt.id} onClick={()=>{setTeams(t=>{const nt=[...t];const pl=nt[ui].ir?.find(p=>p.id===+pid);if(pl){pl.irMin=Math.max(1,(pl.irMin||4)+opt.wkBonus);pl._rehabRisk=opt.risk;}return nt;});setRehabChoices(rc=>{const n={...rc};delete n[pid];return n;});setLog(l=>[`🏥 ${rc.name} rehab: ${opt.lbl} selected`,...l.slice(0,149)]);sm(`Rehab: ${opt.lbl}`);}} style={{background:'#1e293b',color:'#e2e8f0',border:'1px solid #334155',borderRadius:5,padding:'6px 8px',fontSize:11,textAlign:'left',cursor:'pointer'}}><div style={{fontWeight:700,marginBottom:1}}>{opt.lbl}</div><div style={{color:C.mt,fontSize:10}}>{opt.desc}</div></button>)}</div></div>)}</div></div>}
