    {/* v32: Urgent Trade Offer popup */}
    {urgentTrade&&urgentTradeActive&&<div style={{position:"fixed",bottom:16,right:16,zIndex:3000,background:"#0d1424",border:"2px solid #f59e0b",borderRadius:10,padding:12,maxWidth:280,boxShadow:"0 4px 20px #000a"}}><div style={{fontSize:11,color:"#f59e0b",fontWeight:800,letterSpacing:2}}>⚡ URGENT TRADE OFFER — {urgentTradeTimer}s</div><div style={{fontSize:13,fontWeight:700,color:"#e2e8f0",marginTop:4,marginBottom:2}}>{urgentTrade.fromAb} offers: {urgentTrade.offer}</div><div style={{width:"100%",height:3,background:"#1e293b",borderRadius:2,marginBottom:6}}><div style={{width:`${(urgentTradeTimer/45)*100}%`,height:"100%",background:"#f59e0b",borderRadius:2,transition:"width 1s linear"}}/></div><div style={{display:"flex",gap:5}}><Btn onClick={()=>{const nt=[...teams];const p=urgentTrade.player;const fromTm=nt.findIndex(t=>t.id===urgentTrade.fromTm);if(fromTm>=0){nt[fromTm].roster=nt[fromTm].roster.filter(r=>r.id!==p.id);nt[ui].roster.push({...p,salary:+(p.ovr/99*3).toFixed(1),contract:2});}const pk3=draftPicks.find(pk=>pk.owner===ui&&pk.rd===3);if(pk3){nt[urgentTrade.fromTm]&&(nt[fromTm>=0?fromTm:0]._tradePks=[...(nt[fromTm>=0?fromTm:0]._tradePks||[]),pk3]);setDraftPicks(pr=>pr.filter(pk=>pk.id!==pk3.id));}setTeams(nt);setUrgentTrade(null);setUrgentTradeActive(false);setLog(l=>[`⚡ URGENT TRADE: Got ${p.name} (${p.pos} ${p.ovr}ovr) for 3rd-round pick`,...l.slice(0,149)]);sm(`Urgent trade accepted!`);}} bg="#14532d" c="#86efac" style={{flex:1,fontSize:12}}>✅ Accept</Btn><Btn onClick={()=>{setUrgentTrade(null);setUrgentTradeActive(false);}} bg="#7f1d1d" c="#fca5a5" style={{flex:1,fontSize:12}}>✗ Pass</Btn></div></div>}
    {/* v32: Offseason Grade Card modal */}
    {offszGradeOpen&&offszGrade&&<div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.88)",zIndex:3100,display:"flex",alignItems:"center",justifyContent:"center",padding:12}} onClick={()=>setOffszGradeOpen(false)}><div onClick={e=>e.stopPropagation()} style={{background:C.cd,borderRadius:12,padding:16,maxWidth:360,width:"100%",border:"1px solid #38bdf8"}}><div style={{fontSize:15,fontWeight:900,color:"#38bdf8",marginBottom:10}}>📋 OFFSEASON REPORT CARD</div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:6,marginBottom:10}}>{[["Draft Class",offszGrade.draft],["FA Signings",offszGrade.fa],["Cap Efficiency",offszGrade.cap],["Overall Roster",offszGrade.overall]].map(([lbl,grade])=><div key={lbl} style={{background:C.bg,borderRadius:6,padding:"8px 10px",textAlign:"center",border:`1px solid ${grade==='A'?C.gn:grade==='B'?"#38bdf8":grade==='C'?"#f59e0b":C.rd}44`}}><div style={{fontSize:11,color:C.mt,marginBottom:2}}>{lbl}</div><div style={{fontSize:22,fontWeight:900,color:grade==='A'?C.gn:grade==='B'?"#38bdf8":grade==='C'?"#f59e0b":C.rd}}>{grade}</div></div>)}</div><div style={{fontSize:12,color:C.mt,marginBottom:8}}>Avg OVR: <b style={{color:"#e2e8f0"}}>{offszGrade.avgOvr}</b> · Cap Space: <b style={{color:"#e2e8f0"}}>${offszGrade.capSpc}M</b></div><div style={{display:"flex",gap:5}}><Btn onClick={()=>shareViaWebAPI(`${ut?.city} ${ut?.name} Offseason Report`,`📋 ${ut?.city} ${ut?.name} Offseason Grades — Draft: ${offszGrade.draft} | FA: ${offszGrade.fa} | Cap: ${offszGrade.cap} | Overall: ${offszGrade.overall} | Avg OVR ${offszGrade.avgOvr} | #GridironGM`)} bg="#7c3aed22" c="#a78bfa" style={{flex:1,fontSize:12}}>📤 Share</Btn><Btn onClick={()=>setOffszGradeOpen(false)} bg="#334155" style={{flex:1}}>Close</Btn></div></div></div>}
